describe('SyncEngine Lamport Logic', () => {
  let engine: SyncEngine

  beforeEach(async () => {
    setActivePinia(createPinia())
    SyncEngine._resetInstance()

    await db.clearAllData()

    engine = SyncEngine.getInstance()
    vi.clearAllMocks()

    vi.mocked(supabase.auth.getUser).mockResolvedValue({
      data: { user: { id: 'test-user-id' } },
      error: null,
    } as any)

    vi.mocked(supabase.auth.getSession).mockResolvedValue({
      data: { session: { user: { id: 'test-user-id' } } },
      error: null,
    } as any)

    Object.defineProperty(navigator, 'onLine', { value: true, configurable: true })
  })

  it('deve PULL quando server.version > client.version', async () => {
    await db.transactions.add({
      id: 'tx-v-conflict',
      user_id: 'test-user-id',
      title: 'Cliente v1',
      amount: BigInt(100),
      type: 'expense' as const,
      category_id: 'c1',
      wallet_id: 'w1',
      date: new Date().toISOString(),
      sync_status: 'pending',
      version: 1,
      client_updated_at: '2026-01-01T10:00:00Z',
      created_at: '2026-01-01T10:00:00Z',
      deleted: false,
    })

    // Server has newer version (5 > 1) but older timestamp (09:00 < 10:00)
    // Version should win -> PULL
    const mockTable = createMockTable()
    mockTable.maybeSingle.mockResolvedValue({
      data: { version: 5, client_updated_at: '2026-01-01T09:00:00Z', user_id: 'test-user-id' },
      error: null,
    })
    mockTable.single.mockResolvedValue({
      data: {
        id: 'tx-v-conflict',
        user_id: 'test-user-id',
        title: 'Server v5',
        amount: BigInt(500),
        type: 'expense',
        version: 5,
        client_updated_at: '2026-01-01T09:00:00Z'
      },
      error: null,
    })
    vi.mocked(supabase.from).mockReturnValue(mockTable as any)

    await engine.pushDirtyRecords()

    const local = await db.transactions.get('tx-v-conflict')
    expect(local?.title).toBe('Server v5')
    expect(local?.version).toBe(5)
  })

  it('deve PUSH quando client.version > server.version', async () => {
    await db.transactions.add({
      id: 'tx-client-v2',
      user_id: 'test-user-id',
      title: 'Cliente v2',
      amount: BigInt(200),
      type: 'expense' as const,
      category_id: 'c1',
      wallet_id: 'w1',
      date: new Date().toISOString(),
      sync_status: 'pending',
      version: 2,
      client_updated_at: '2026-01-01T12:00:00Z',
      created_at: '2026-01-01T12:00:00Z',
      deleted: false,
    })

    // Client has newer version (2 > 1) but older timestamp (09:00 < 10:00)
    // Version should win -> PUSH
    const mockTable = createMockTable()
    mockTable.maybeSingle.mockResolvedValue({
      data: { version: 1, client_updated_at: '2026-01-01T10:00:00Z', user_id: 'test-user-id' },
      error: null,
    })
    vi.mocked(supabase.from).mockReturnValue(mockTable as any)

    await engine.pushDirtyRecords()

    expect(mockTable.upsert).toHaveBeenCalled()
    const local = await db.transactions.get('tx-client-v2')
    expect(local?.sync_status).toBe('synced')
  })

  it('deve usar LWW (timestamp) como tie-breaker quando as versões são iguais', async () => {
    const olderTime = '2026-01-01T10:00:00Z'
    const newerTime = '2026-01-01T11:00:00Z'

    await db.transactions.add({
      id: 'tx-tie',
      user_id: 'test-user-id',
      title: 'Cliente Antigo',
      amount: BigInt(100),
      type: 'expense' as const,
      category_id: 'c1',
      wallet_id: 'w1',
      date: olderTime,
      sync_status: 'pending',
      version: 3,
      client_updated_at: olderTime,
      created_at: olderTime,
      deleted: false,
    })

    const mockTable = createMockTable()
    mockTable.maybeSingle.mockResolvedValue({
      data: { version: 3, client_updated_at: newerTime, user_id: 'test-user-id' },
      error: null,
    })
    mockTable.single.mockResolvedValue({
      data: {
        id: 'tx-tie',
        user_id: 'test-user-id',
        title: 'Server Novo',
        amount: BigInt(500),
        version: 3,
        client_updated_at: newerTime
      },
      error: null,
    })
    vi.mocked(supabase.from).mockReturnValue(mockTable as any)

    await engine.pushDirtyRecords()

    const local = await db.transactions.get('tx-tie')
    expect(local?.title).toBe('Server Novo')
  })
})

/**
 * Theme Injector: Prevents FOUC (Flash of Unstyled Content) by setting the dark mode class
 * before the main Vue app is initialized. Also injects CSS variables for Chart.js theming.
 * Reference: openspec/changes/apple-design-system-refactor/
 */
(function() {
  const theme = localStorage.getItem('divi-ui-theme') || 'system';
  const isDark = theme === 'dark' || (theme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches);

  if (isDark) {
    document.documentElement.classList.add('dark');
  } else {
    document.documentElement.classList.remove('dark');
  }

  // Inject CSS variables for Chart.js theming — Apple HIG palette
  function injectChartColors() {
    const root = document.documentElement;
    const isDarkMode = root.classList.contains('dark');

    // Primary accent — Apple System Blue
    root.style.setProperty('--color-accent-main', isDarkMode ? '#0A84FF' : '#007AFF');

    // Surface colors for chart backgrounds / tooltips
    root.style.setProperty('--color-surface-100', isDarkMode ? '#1C1C1E' : '#FFFFFF');
    root.style.setProperty('--color-surface-200', isDarkMode ? '#2C2C2E' : '#F2F2F7');

    // Neutral colors for axis text — Apple alpha hierarchy
    root.style.setProperty('--color-neutral-1', isDarkMode ? 'rgba(255,255,255,0.85)' : 'rgba(0,0,0,0.85)');
    root.style.setProperty('--color-neutral-2', isDarkMode ? 'rgba(235,235,245,0.6)' : 'rgba(60,60,67,0.6)');

    // Feedback colors — Apple system semantic colors
    root.style.setProperty('--color-error-main',   isDarkMode ? '#FF453A' : '#FF3B30');
    root.style.setProperty('--color-success-main', isDarkMode ? '#30D158' : '#34C759');
    root.style.setProperty('--color-info-main',    isDarkMode ? '#0A84FF' : '#007AFF');
    root.style.setProperty('--color-warning-main', isDarkMode ? '#FF9F0A' : '#FF9500');

    // Separator for chart grid lines
    root.style.setProperty('--color-separator', isDarkMode ? 'rgba(84,84,88,0.65)' : 'rgba(60,60,67,0.12)');
  }

  // Initial injection
  injectChartColors();

  // Listen for theme toggle events
  window.addEventListener('storage', (e) => {
    if (e.key === 'divi-ui-theme') {
      const newTheme = e.newValue || 'system';
      const isNewDarkMode = newTheme === 'dark' || (newTheme === 'system' && window.matchMedia('(prefers-color-scheme: dark)').matches);
      if (isNewDarkMode) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      injectChartColors();
    }
  });

  // Also listen for system preference changes
  window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', () => {
    const currentTheme = localStorage.getItem('divi-ui-theme') || 'system';
    if (currentTheme === 'system') {
      const isSystemDarkMode = window.matchMedia('(prefers-color-scheme: dark)').matches;
      if (isSystemDarkMode) {
        document.documentElement.classList.add('dark');
      } else {
        document.documentElement.classList.remove('dark');
      }
      injectChartColors();
    }
  });
})();

import type { ILogger } from '../../core/logger/ILogger';

/**
 * Console-based implementation of ILogger.
 * Strictly adheres to Constitution Rule XIII.
 */
export class ConsoleLogger implements ILogger {
  private readonly context: string;

  constructor(context: string = 'App') {
    this.context = context;
  }

  private format(level: string, message: string): string {
    const timestamp = new Date().toISOString();
    return `[${timestamp}] [${level}] [${this.context}]: ${message}`;
  }

  public debug(message: string, ...args: any[]): void {
    console.debug(this.format('DEBUG', message), ...args);
  }

  public info(message: string, ...args: any[]): void {
    console.info(this.format('INFO', message), ...args);
  }

  public warn(message: string, ...args: any[]): void {
    console.warn(this.format('WARN', message), ...args);
  }

  public error(message: string, error?: Error, ...args: any[]): void {
    console.error(this.format('ERROR', message), error, ...args);
  }
}

