import type { IVaultCryptoManager } from '../../core/ports/IVaultCryptoManager'
import type { ISyncEngine } from '@/core/sync/ports/ISyncEngine'
import { container } from '@/core/di'
import { DI_TOKENS } from '@/core/di-tokens'

// Mocks para dependências externas
vi.mock('@/infrastructure/storage/VaultDatabase', () => ({
  vaultDb: {
    clearAllData: vi.fn().mockResolvedValue(undefined),
  },
}))

const createMockAuthService = (overrides?: Partial<IAuthService>): IAuthService => ({
  signInWithGoogle: vi.fn(),
  signInWithEmail: vi.fn(),
  registerWithEmail: vi.fn(),
  signOut: vi.fn().mockResolvedValue(undefined),
  getCurrentUser: vi.fn().mockResolvedValue(null),
  onAuthStateChange: vi.fn(),
  deleteAccountData: vi.fn().mockResolvedValue(undefined),
  ...overrides,
})

const createMockVaultCryptoManager = (overrides?: Partial<IVaultCryptoManager>): IVaultCryptoManager => ({
  lock: vi.fn(),
  initialize: vi.fn().mockResolvedValue(undefined),
  hasKey: vi.fn().mockReturnValue(false),
  encrypt: vi.fn().mockResolvedValue({ encrypted: '', iv: '', salt: '', tag: '' }),
  decrypt: vi.fn().mockResolvedValue(''),
  ...overrides,
})

const createMockSyncEngine = (overrides?: Partial<ISyncEngine>): ISyncEngine => ({
  trigger: vi.fn().mockResolvedValue(undefined),
  enqueueSync: vi.fn(),
  pushDirtyRecords: vi.fn().mockResolvedValue(undefined),
  pullFromServer: vi.fn().mockResolvedValue(undefined),
  ...overrides,
})

describe('Auth Store', () => {
  let authService: IAuthService
  let vaultCryptoManager: IVaultCryptoManager
  let syncEngine: ISyncEngine

  beforeEach(() => {
    setActivePinia(createPinia())
    vi.clearAllMocks()

    authService = createMockAuthService()
    vaultCryptoManager = createMockVaultCryptoManager()
    syncEngine = createMockSyncEngine()

    container.register(DI_TOKENS.IAuthService, authService)
    container.register(DI_TOKENS.IVaultCryptoManager, vaultCryptoManager)
    container.register(DI_TOKENS.ISyncEngine, syncEngine)
  })

  it('should initialize with no user', () => {
    const store = useAuthStore()
    expect(store.user).toBeNull()
    expect(store.isAuthenticated).toBe(false)
  })

  it('should set user correctly', () => {
    const store = useAuthStore()
    store.setUser({ id: '1', email: 'test@example.com' })
    expect(store.user).toEqual({ id: '1', email: 'test@example.com' })
    expect(store.isAuthenticated).toBe(true)
  })

  it('should clear user correctly', () => {
    const store = useAuthStore()
    store.setUser({ id: '1', email: 'test@example.com' })
    store.clearUser()
    expect(store.user).toBeNull()
    expect(store.isAuthenticated).toBe(false)
  })

  describe('purgeAccount', () => {
    it('should call deleteAccountData on auth service', async () => {
      const store = useAuthStore()
      store.setUser({ id: '1', email: 'test@example.com' })

      await store.purgeAccount()

      expect(authService.deleteAccountData).toHaveBeenCalledOnce()
    })

    it('should clear local database', async () => {
      const { vaultDb } = await import('@/infrastructure/storage/VaultDatabase')
      const store = useAuthStore()
      store.setUser({ id: '1', email: 'test@example.com' })

      await store.purgeAccount()

      expect(vaultDb.clearAllData).toHaveBeenCalledOnce()
    })

    it('should lock the crypto vault', async () => {
      const store = useAuthStore()
      store.setUser({ id: '1', email: 'test@example.com' })

      await store.purgeAccount()

      expect(vaultCryptoManager.lock).toHaveBeenCalledOnce()
    })

    it('should call signOut on auth service', async () => {
      const store = useAuthStore()
      store.setUser({ id: '1', email: 'test@example.com' })

      await store.purgeAccount()

      expect(authService.signOut).toHaveBeenCalledOnce()
    })

    it('should clear user state after purge', async () => {
      const store = useAuthStore()
      store.setUser({ id: '1', email: 'test@example.com' })

      await store.purgeAccount()

      expect(store.user).toBeNull()
      expect(store.isAuthenticated).toBe(false)
    })

    it('should propagate error if deleteAccountData fails', async () => {
      const store = useAuthStore()
      store.setUser({ id: '1', email: 'test@example.com' })

      const failingAuthService = createMockAuthService({
        deleteAccountData: vi.fn().mockRejectedValue(new Error('Network error')),
      })
      container.register(DI_TOKENS.IAuthService, failingAuthService)

      await expect(store.purgeAccount()).rejects.toThrow('Network error')
    })
  })

  describe('initialize', () => {
    it('should initialize with current user', async () => {
      const store = useAuthStore()
      const customAuthService = createMockAuthService({
        getCurrentUser: vi.fn().mockResolvedValue({ id: '1', email: 'test@example.com' }),
      })
      container.register(DI_TOKENS.IAuthService, customAuthService)

      await store.initialize()

      expect(store.user).toEqual({ id: '1', email: 'test@example.com' })
      expect(store.isAuthenticated).toBe(true)
    })

    it('should lock vault on logout', async () => {
      const store = useAuthStore()

      let authStateCallback: ((user: null) => void) | null = null
      authService.onAuthStateChange = vi.fn((callback) => {
        authStateCallback = callback
      })

      await store.initialize()

      authStateCallback?.(null)

      expect(vaultCryptoManager.lock).toHaveBeenCalledOnce()
    })

    it('should trigger sync on login', async () => {
      const store = useAuthStore()

      let authStateCallback: ((user: { id: string; email: string }) => void) | null = null
      authService.onAuthStateChange = vi.fn((callback) => {
        authStateCallback = callback
      })

      await store.initialize()

      authStateCallback?.({ id: '1', email: 'test@example.com' })

      expect(syncEngine.trigger).toHaveBeenCalledOnce()
    })
  })

  describe('initializeVault', () => {
    it('should initialize vault with password', async () => {
      const store = useAuthStore()

      await store.initializeVault('password123')

      expect(vaultCryptoManager.initialize).toHaveBeenCalledWith('password123')
    })

    it('should trigger sync after vault initialization', async () => {
      const store = useAuthStore()

      await store.initializeVault('password123')

      expect(syncEngine.trigger).toHaveBeenCalledOnce()
    })
  })
})

import { setActivePinia, createPinia } from 'pinia'
import { describe, it, expect, vi, beforeEach, type Mock } from 'vitest'
import { useAuthStore } from '../authStore'
import type { IAuthService } from '../../core/ports/IAuthService'
import type { IUser } from '../../core/entities/IUser'
import { container } from '@/core/di'
import { DI_TOKENS } from '@/core/di-tokens'

describe('Auth Persistence Integration', () => {
  let authService: {
    getCurrentUser: Mock
    onAuthStateChange: Mock
    signOut: Mock
    signInWithGoogle: Mock
    signInWithEmail: Mock
    registerWithEmail: Mock
    deleteAccountData: Mock
  }
  let vaultCryptoManager: {
    lock: Mock
  }
  let syncEngine: {
    trigger: Mock
  }

  beforeEach(() => {
    setActivePinia(createPinia())
    authService = {
      getCurrentUser: vi.fn(),
      onAuthStateChange: vi.fn(),
      signOut: vi.fn(),
      signInWithGoogle: vi.fn(),
      signInWithEmail: vi.fn(),
      registerWithEmail: vi.fn(),
      deleteAccountData: vi.fn().mockResolvedValue(undefined),
    }
    vaultCryptoManager = {
      lock: vi.fn(),
    }
    syncEngine = {
      trigger: vi.fn(),
    }

    container.register(DI_TOKENS.IAuthService, authService)
    container.register(DI_TOKENS.IVaultCryptoManager, vaultCryptoManager)
    container.register(DI_TOKENS.ISyncEngine, syncEngine)
  })

  it('should recover user session from service on initialization', async () => {
    const mockUser: IUser = { id: '123', email: 'persisted@test.com' }
    authService.getCurrentUser.mockResolvedValueOnce(mockUser)

    const store = useAuthStore()

    await store.initialize()

    expect(store.user).toEqual(mockUser)
    expect(store.isAuthenticated).toBe(true)
  })

  it('should update store when auth state changes in the service', async () => {
    const store = useAuthStore()
    let authCallback: (user: IUser | null) => void = () => {}

    authService.onAuthStateChange.mockImplementation((cb: (user: IUser | null) => void) => {
      authCallback = cb
    })

    await store.initialize()

    const newUser: IUser = { id: '456', email: 'new@test.com' }
    authCallback(newUser)

    expect(store.user).toEqual(newUser)
    expect(store.isAuthenticated).toBe(true)
    expect(syncEngine.trigger).toHaveBeenCalled()

    authCallback(null)
    expect(store.user).toBeNull()
    expect(store.isAuthenticated).toBe(false)
    expect(vaultCryptoManager.lock).toHaveBeenCalled()
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { SupabaseAuthService as SupabaseAuth } from '../../adapters/SupabaseAuthService'
import { supabase } from '@/core/supabase'
import type {
  UserResponse,
  AuthChangeEvent,
  Session,
  User,
} from '@supabase/supabase-js'

// Helper para criar um mock de tabela Supabase com método delete em cadeia
const createDeleteMock = (error: Error | null = null) => ({
  delete: vi.fn().mockReturnValue({
    eq: vi.fn().mockResolvedValue({ error }),
  }),
})

vi.mock('@/core/supabase', () => ({
  supabase: {
    auth: {
      signInWithOAuth: vi.fn(),
      signInWithPassword: vi.fn(),
      signUp: vi.fn(),
      signOut: vi.fn(),
      getUser: vi.fn(),
      getSession: vi.fn(),
      onAuthStateChange: vi.fn(),
    },
    from: vi.fn(),
  },
}))

describe('SupabaseAuth', () => {
  let authService: SupabaseAuth

  beforeEach(() => {
    vi.clearAllMocks()
    authService = new SupabaseAuth(supabase)
  })

  it('should call signInWithPassword when signInWithEmail is called', async () => {
    vi.mocked(supabase.auth.signInWithPassword).mockResolvedValueOnce({
      data: { user: {} as any, session: {} as any },
      error: null,
    } as any)
    await authService.signInWithEmail({ email: 'test@example.com', password: 'password123' })
    expect(supabase.auth.signInWithPassword).toHaveBeenCalledWith({
      email: 'test@example.com',
      password: 'password123',
    })
  })

  it('should throw error when signInWithEmail fails', async () => {
    vi.mocked(supabase.auth.signInWithPassword).mockResolvedValueOnce({
      data: { user: null, session: null },
      error: new Error('Invalid credentials') as any,
    } as any)

    await expect(
      authService.signInWithEmail({ email: 'test@example.com', password: 'password123' }),
    ).rejects.toThrow('Invalid credentials')
  })

  it('should call signUp when registerWithEmail is called', async () => {
    vi.mocked(supabase.auth.signUp).mockResolvedValueOnce({
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      data: { user: {} as any, session: {} as any },
      error: null,
    } as any)
    await authService.registerWithEmail({ email: 'test@example.com', password: 'password123' })
    expect(supabase.auth.signUp).toHaveBeenCalledWith({
      email: 'test@example.com',
      password: 'password123',
    })
  })

  it('should throw error when registerWithEmail fails', async () => {
    vi.mocked(supabase.auth.signUp).mockResolvedValueOnce({
      data: { user: null, session: null },
      error: new Error('Email already exists') as any,
    } as any)

    await expect(
      authService.registerWithEmail({ email: 'test@example.com', password: 'password123' }),
    ).rejects.toThrow('Email already exists')
  })

  it('should call signInWithOAuth when signInWithGoogle is called', async () => {
    vi.mocked(supabase.auth.signInWithOAuth).mockResolvedValueOnce({
      data: { provider: 'google', url: 'http://redirect.com' },
      error: null,
    } as any)
    await authService.signInWithGoogle()
    expect(supabase.auth.signInWithOAuth).toHaveBeenCalledWith({
      provider: 'google',
      options: {
        redirectTo: expect.any(String),
      },
    })
  })

  it('should call signOut on supabase auth', async () => {
    vi.mocked(supabase.auth.signOut).mockResolvedValueOnce({ error: null } as any)
    await authService.signOut()
    expect(supabase.auth.signOut).toHaveBeenCalled()
  })

  it('should return mapped User when getCurrentUser is called', async () => {
    const mockSupabaseUser = {
      id: '123',
      email: 'test@test.com',
      user_metadata: {
        full_name: 'Test User',
        avatar_url: 'http://test.com/avatar.png',
      },
    }
    vi.mocked(supabase.auth.getSession).mockResolvedValueOnce({
      data: { session: { user: mockSupabaseUser } as any },
      error: null,
    } as any)
    vi.mocked(supabase.auth.getUser).mockResolvedValueOnce({
      data: { user: mockSupabaseUser as unknown as User },
      error: null,
    } as UserResponse)

    const user = await authService.getCurrentUser()

    expect(supabase.auth.getSession).toHaveBeenCalled()
    expect(user).toEqual({
      id: '123',
      email: 'test@test.com',
      name: 'Test User',
      avatar_url: 'http://test.com/avatar.png',
    })
  })

  it('should return null when getCurrentUser has no user', async () => {
    vi.mocked(supabase.auth.getSession).mockResolvedValueOnce({
      data: { session: null },
      error: null,
    } as any)

    const user = await authService.getCurrentUser()
    expect(user).toBeNull()
  })

  it('should register onAuthStateChange callback and handle user session', () => {
    const callback = vi.fn()

    // Simulate Supabase calling our callback with a session
    vi.mocked(supabase.auth.onAuthStateChange).mockImplementationOnce((cb) => {
      cb(
        'SIGNED_IN' as AuthChangeEvent,
        {
          user: {
            id: '123',
            email: 'test@test.com',
            user_metadata: {
              full_name: 'Test User',
            },
          },
        } as unknown as Session,
      )
      return {
        data: { subscription: { unsubscribe: vi.fn(), id: '1', callback: vi.fn() } },
      } as unknown as ReturnType<typeof supabase.auth.onAuthStateChange>
    })

    authService.onAuthStateChange(callback)

    expect(supabase.auth.onAuthStateChange).toHaveBeenCalled()
    expect(callback).toHaveBeenCalledWith({
      id: '123',
      email: 'test@test.com',
      name: 'Test User',
      avatar_url: undefined,
    })
  })

  it('should register onAuthStateChange callback and handle no session', () => {
    const callback = vi.fn()

    // Simulate Supabase calling our callback without a session user
    vi.mocked(supabase.auth.onAuthStateChange).mockImplementationOnce((cb) => {
      cb('SIGNED_OUT' as AuthChangeEvent, null)
      return {
        data: { subscription: { unsubscribe: vi.fn(), id: '1', callback: vi.fn() } },
      } as unknown as ReturnType<typeof supabase.auth.onAuthStateChange>
    })

    authService.onAuthStateChange(callback)

    expect(supabase.auth.onAuthStateChange).toHaveBeenCalled()
    expect(callback).toHaveBeenCalledWith(null)
  })

  describe('deleteAccountData', () => {
    beforeEach(() => {
      vi.mocked(supabase.auth.getUser).mockResolvedValue({
        data: { user: { id: '123' } as any },
        error: null,
      } as any)
    })

    it('should delete records from all syncable tables successfully', async () => {
      const mockDeleteTable = createDeleteMock(null)
      vi.mocked(supabase.from).mockReturnValue(mockDeleteTable as any)

      await authService.deleteAccountData()

      // USER_DATA_TABLES has 7 tables
      expect(supabase.from).toHaveBeenCalledTimes(7)
      expect(supabase.from).toHaveBeenCalledWith('transactions')
      expect(supabase.from).toHaveBeenCalledWith('wallets')
      expect(supabase.from).toHaveBeenCalledWith('categories')
      expect(supabase.from).toHaveBeenCalledWith('loans')
      expect(supabase.from).toHaveBeenCalledWith('subscriptions')
      expect(supabase.from).toHaveBeenCalledWith('budgets')
      expect(supabase.from).toHaveBeenCalledWith('goals')
    })

    it('should call .delete().eq() on each table', async () => {
      const mockDeleteTable = createDeleteMock(null)
      vi.mocked(supabase.from).mockReturnValue(mockDeleteTable as any)

      await authService.deleteAccountData()

      expect(mockDeleteTable.delete).toHaveBeenCalledTimes(7)
      expect(mockDeleteTable.delete().eq).toHaveBeenCalledWith(
        'user_id',
        '123',
      )
    })

    it('should throw an error when one table fails to delete', async () => {
      const successMock = createDeleteMock(null)
      const failMock = createDeleteMock(new Error('RLS policy violation'))

      vi.mocked(supabase.from)
        .mockReturnValueOnce(successMock as any) // transactions
        .mockReturnValueOnce(failMock as any)    // wallets — fails
        .mockReturnValue(successMock as any)     // remaining tables

      await expect(authService.deleteAccountData()).rejects.toThrow('Purge parcialmente falhou em')
    })

    it('should continue deleting other tables even if one fails', async () => {
      const successMock = createDeleteMock(null)
      const failMock = createDeleteMock(new Error('policy error'))

      // wallets (index 1) fails, all others succeed
      vi.mocked(supabase.from)
        .mockReturnValueOnce(successMock as any) // transactions
        .mockReturnValueOnce(failMock as any)    // wallets — fails
        .mockReturnValue(successMock as any)

      await expect(authService.deleteAccountData()).rejects.toThrow()

      // Should have tried all 7 tables despite failure
      expect(supabase.from).toHaveBeenCalledTimes(7)
    })
  })
})

