describe('Budgets Integration', () => {
  beforeEach(async () => {
    setActivePinia(createPinia())
    await db.budgets.clear()
    await db.transactions.clear()
    await db.categories.clear()
  })

  it('should reactively update budget consumption when transactions change', async () => {
    // 1. Setup Data
    const category = { id: 'c1', name: 'Food', user_id: 'u1', deleted: false } as any
    await db.categories.add(category)

    const budgetStore = useBudgetStore()
    const transactionStore = useTransactionStore()

    // 2. Initialize Store
    budgetStore.initialize()

    // 3. Create IBudget
    await budgetStore.saveBudget({
      category_id: 'c1',
      limit_value: 1000n,
      period: 'monthly',
    } as any)

    // Wait for liveQuery
    await new Promise((resolve) => setTimeout(resolve, 100))
    expect(budgetStore.budgets.length).toBe(1)

    // 4. Initial Consumption (0)
    expect(budgetStore.getConsumed(budgetStore.budgets[0]!)).toBe(0)

    // 5. Add ITransaction
    await transactionStore.saveITransaction({
      id: 't1',
      title: 'Dinner',
      amount: 150n,
      category_id: 'c1',
      wallet_id: 'w1',
      date: new Date().toISOString(),
      type: 'expense',
    } as any)

    // 6. Verify Reactive Update
    // In a real integration, we'd wait for transactionStore to update its internal 'transactions' ref
    // But transactionStore update logic might be complex.
    // For this test, let's assume transactionStore.transactions is updated by saveITransaction call.

    // Wait for any async effects
    await new Promise((resolve) => setTimeout(resolve, 100))

    // Check if consumed increased
    const consumed = budgetStore.getConsumed(budgetStore.budgets[0]!)
    expect(consumed).toBe(150)

    budgetStore.dispose()
  })
})

import { liveQuery } from 'dexie'
import { from, type Observable } from 'rxjs'
import { v7 as uuidv7 } from 'uuid'
import type { IBudgetRepository } from '../core/ports/IBudgetRepository'
import type { IBudget } from '@/modules/budgets/core/entities/IBudget'
import { vaultDb as db } from '@/infrastructure/storage/VaultDatabase'
import { SyncEngine } from '@/core/sync/SyncEngine'

export class DexieBudgetRepository implements IBudgetRepository {
  async getAllActive(): Promise<IBudget[]> {
    const budgets = await db.budgets.filter((b) => !b.deleted).toArray()
    return budgets as IBudget[]
  }

  watchAll(): Observable<IBudget[]> {
    return from(
      liveQuery(() => db.budgets.filter((b) => !b.deleted).toArray()) as unknown as Observable<
        IBudget[]
      >,
    )
  }

  async create(budget: Omit<IBudget, 'id' | 'created_at' | 'client_updated_at' | 'sync_status' | 'version' | 'deleted'>): Promise<IBudget> {
    try {
      const id = uuidv7()
      const created_at = new Date().toISOString()
      const version = 1
      const deleted = false
      const sync_status = 'pending' as const

      await db.transaction('rw', db.budgets, async () => {
        const data = {
          ...budget,
          id,
          limit_value: BigInt(budget.limit_value ?? 0),
          sync_status,
          client_updated_at: created_at,
          created_at,
          deleted,
          version,
        }
        await db.budgets.put(data)
      })
      SyncEngine.getInstance().enqueueSync()
      const result = await db.budgets.get(id)
      return result as IBudget
    } catch (err) {
      console.error('[DexieBudgetRepository] Failed to create budget', err)
      throw err
    }
  }

  async update(id: string, budget: Partial<IBudget>): Promise<IBudget> {
    try {
      await db.transaction('rw', db.budgets, async () => {
        await db.budgets.update(id, {
          ...budget,
          limit_value: budget.limit_value !== undefined ? BigInt(budget.limit_value) : undefined,
          sync_status: 'pending',
          client_updated_at: new Date().toISOString(),
        })
      })
      SyncEngine.getInstance().enqueueSync()
      const result = await db.budgets.get(id)
      return result as IBudget
    } catch (err) {
      console.error('[DexieBudgetRepository] Failed to update budget', err)
      throw err
    }
  }

  async delete(id: string): Promise<void> {
    try {
      await db.transaction('rw', db.budgets, async () => {
        await db.budgets.update(id, {
          deleted: true,
          sync_status: 'pending',
          client_updated_at: new Date().toISOString(),
        })
      })
      SyncEngine.getInstance().enqueueSync()
    } catch (err) {
      console.error('[DexieBudgetRepository] Failed to delete budget', err)
      throw err
    }
  }
}

